     3→import { join } from 'path'
     4→import type { Workspace, Project, ProjectCategory } from './session-store'
     5→
     6→const UNCATEGORIZED_FOLDER = 'Uncategorized'
     7→
     8→/**
     9→ * Get the base path for meta-projects symlink structure
    10→ */
    11→function getMetaProjectsBasePath(): string {
    12→  return join(app.getPath('userData'), 'meta-projects')
    13→}
    14→
    15→/**
    16→ * Get current symlinks in a category directory
    17→ * Returns map of symlink name -> target path
    18→ */
    19→function getCurrentSymlinks(categoryDir: string): Map<string, string> {
    20→  const symlinks = new Map<string, string>()
    21→  if (!existsSync(categoryDir)) return symlinks
    22→
    23→  try {
    24→    const entries = readdirSync(categoryDir)
    25→    for (const entry of entries) {
    26→      const entryPath = join(categoryDir, entry)
    27→      try {
    28→        const stat = lstatSync(entryPath)
    29→        if (stat.isSymbolicLink()) {
    30→          const target = readlinkSync(entryPath)
    31→          symlinks.set(entry, target)
    32→        }
    33→      } catch {
    34→        // Skip entries we can't stat
    35→      }
    36→    }
    37→  } catch {
    38→    // Directory might not exist or be readable
    39→  }
    40→  return symlinks
    41→}
    42→
    43→/**
    44→ * Remove a single symlink
    45→ */
    46→function removeSymlink(symlinkPath: string): void {
    47→  try {
    48→    if (existsSync(symlinkPath)) {
    49→      const stat = lstatSync(symlinkPath)
    50→      if (stat.isSymbolicLink()) {
    51→        unlinkSync(symlinkPath)
    52→      }
    53→    }
    54→  } catch (e) {
    55→    console.warn(`Failed to remove symlink ${symlinkPath}:`, e)
    56→  }
    57→}
    58→
    59→/**
    60→ * Remove an empty category directory (only if it's empty)
    61→ */
    62→function removeEmptyCategoryDir(categoryDir: string): void {
    63→  if (!existsSync(categoryDir)) return
    64→
    65→  try {
    66→    const entries = readdirSync(categoryDir)
    67→    if (entries.length === 0) {
    68→      rmSync(categoryDir, { recursive: true, force: true })
    69→    }
    70→  } catch (e) {
    71→    console.warn(`Failed to remove empty category dir ${categoryDir}:`, e)
    72→  }
    73→}
    74→
    75→/**
    76→ * Generate a unique symlink name by appending numbers if needed
    77→ */
    78→function getUniqueSymlinkName(dir: string, baseName: string, existingNames: Set<string>): string {
    79→  // Sanitize name for filesystem
    80→  let name = baseName.replace(/[/\\:*?"<>|]/g, '_')
    81→
    82→  if (!existingNames.has(name)) {
    83→    existingNames.add(name)
    84→    return name
    85→  }
    86→
    87→  // Append numbers until unique
    88→  let counter = 2
    89→  while (existingNames.has(`${name}-${counter}`)) {
    90→    counter++
    91→  }
    92→
    93→  const uniqueName = `${name}-${counter}`
    94→  existingNames.add(uniqueName)
    95→  return uniqueName
    96→}
    97→
    98→/**
    99→ * Create a symlink, handling errors gracefully
   100→ */
   101→function createSymlink(targetPath: string, symlinkPath: string): boolean {
   102→  try {
   103→    // Verify target path exists
   104→    if (!existsSync(targetPath)) {
   105→      console.warn(`Skipping symlink for non-existent path: ${targetPath}`)
   106→      return false
   107→    }
   108→
   109→    symlinkSync(targetPath, symlinkPath)
   110→    return true
   111→  } catch (e) {
   112→    console.warn(`Failed to create symlink ${symlinkPath} -> ${targetPath}:`, e)
   113→    return false
   114→  }
   115→}
   116→
   117→/**
   118→ * Build category map from workspace
   119→ */
   120→function buildCategoryMap(categories: ProjectCategory[] | undefined): Map<string, string> {
   121→  const map = new Map<string, string>()
   122→  if (categories) {
   123→    for (const cat of categories) {
   124→      map.set(cat.id, cat.name)
   125→    }
   126→  }
   127→  return map
   128→}
   129→
   130→/**
   131→ * Group projects by category
   132→ */
   133→function groupProjectsByCategory(
   134→  projects: Project[],
   135→  categoryMap: Map<string, string>
   136→): Map<string, Project[]> {
   137→  const groups = new Map<string, Project[]>()
   138→
   139→  for (const project of projects) {
   140→    let categoryName: string
   141→
   142→    if (project.categoryId && categoryMap.has(project.categoryId)) {
   143→      categoryName = categoryMap.get(project.categoryId)!
   144→    } else {
   145→      categoryName = UNCATEGORIZED_FOLDER
   146→    }
   147→
   148→    // Sanitize category name for filesystem
   149→    categoryName = categoryName.replace(/[/\\:*?"<>|]/g, '_')
   150→
   151→    if (!groups.has(categoryName)) {
   152→      groups.set(categoryName, [])
   153→    }
   154→    groups.get(categoryName)!.push(project)
   155→  }
   156→
   157→  return groups
   158→}
   159→
   160→/**
   161→ * Sync workspace projects to meta-projects symlink structure
   162→ *
   163→ * Creates a hierarchical symlink structure mirroring workspace categories:
   164→ * ~/.config/simple-code-gui/meta-projects/
   165→ * ├── Work/
   166→ * │   ├── ProjectA -> /home/user/work/ProjectA
   167→ * │   └── ProjectB -> /home/user/work/ProjectB
   168→ * ├── Personal/
   169→ * │   └── MyApp -> /home/user/Projects/MyApp
   170→ * └── Uncategorized/
   171→ *     └── RandomProject -> /home/user/RandomProject
   172→ *
   173→ * IMPORTANT: This function does incremental updates to avoid breaking
   174→ * running sessions that have their cwd in a category folder. It only
   175→ * removes/adds symlinks as needed rather than deleting entire directories.
   176→ */
   177→export function syncMetaProjects(workspace: Workspace): void {
   178→  const basePath = getMetaProjectsBasePath()
   179→
   180→  // Ensure base directory exists
   181→  if (!existsSync(basePath)) {
   182→    try {
   183→      mkdirSync(basePath, { recursive: true })
   184→    } catch (e) {
   185→      console.error('Failed to create meta-projects directory:', e)
   186→      return
   187→    }
   188→  }
   189→
   190→  // Build category mapping
   191→  const categoryMap = buildCategoryMap(workspace.categories)
   192→
   193→  // Group projects by category
   194→  const projectGroups = groupProjectsByCategory(workspace.projects, categoryMap)
   195→
   196→  // Track which category dirs should exist
   197→  const expectedCategoryDirs = new Set<string>()
   198→  for (const categoryName of projectGroups.keys()) {
   199→    expectedCategoryDirs.add(categoryName)
   200→  }
   201→
   202→  // Process each category - add/update symlinks
   203→  for (const [categoryName, projects] of projectGroups) {
   204→    const categoryDir = join(basePath, categoryName)
   205→
   206→    // Create category directory if it doesn't exist
   207→    if (!existsSync(categoryDir)) {
   208→      try {
   209→        mkdirSync(categoryDir, { recursive: true })
   210→      } catch (e) {
   211→        console.warn(`Failed to create category directory ${categoryDir}:`, e)
   212→        continue
   213→      }
   214→    }
   215→
   216→    // Get current symlinks in this category
   217→    const currentSymlinks = getCurrentSymlinks(categoryDir)
   218→
   219→    // Build map of what symlinks should exist (project path -> desired symlink name)
   220→    const desiredSymlinks = new Map<string, string>()
   221→    const usedNames = new Set<string>()
   222→
   223→    for (const project of projects) {
   224→      const symlinkName = getUniqueSymlinkName(categoryDir, project.name, usedNames)
   225→      desiredSymlinks.set(project.path, symlinkName)
   226→    }
   227→
   228→    // Remove symlinks that shouldn't exist or point to wrong targets
   229→    for (const [name, target] of currentSymlinks) {
   230→      // Check if this symlink is still needed
   231→      let shouldKeep = false
   232→      for (const [projectPath, desiredName] of desiredSymlinks) {
   233→        if (target === projectPath && name === desiredName) {
   234→          shouldKeep = true
   235→          break
   236→        }
   237→      }
   238→      if (!shouldKeep) {
   239→        removeSymlink(join(categoryDir, name))
   240→      }
   241→    }
   242→
   243→    // Refresh current symlinks after removals
   244→    const remainingSymlinks = getCurrentSymlinks(categoryDir)
   245→    const existingTargets = new Set(remainingSymlinks.values())
   246→
   247→    // Create new symlinks that don't exist yet
   248→    for (const [projectPath, symlinkName] of desiredSymlinks) {
   249→      if (!existingTargets.has(projectPath)) {
   250→        createSymlink(projectPath, join(categoryDir, symlinkName))
   251→      }
   252→    }
   253→  }
   254→
   255→  // Remove category directories that shouldn't exist anymore
   256→  // But only remove symlinks inside, keep the directory if it still has content
   257→  try {
   258→    const existingDirs = readdirSync(basePath)
   259→    for (const dirName of existingDirs) {
   260→      if (!expectedCategoryDirs.has(dirName)) {
   261→        const dirPath = join(basePath, dirName)
   262→        const stat = lstatSync(dirPath)
   263→        if (stat.isDirectory() && !stat.isSymbolicLink()) {
   264→          // Remove all symlinks in this directory
   265→          const symlinks = getCurrentSymlinks(dirPath)
   266→          for (const name of symlinks.keys()) {
   267→            removeSymlink(join(dirPath, name))
   268→          }
   269→          // Try to remove directory if empty
   270→          removeEmptyCategoryDir(dirPath)
   271→        }
   272→      }
   273→    }
   274→  } catch (e) {
   275→    console.warn('Failed to clean up old category directories:', e)
   276→  }
   277→}
   278→
   279→/**
   280→ * Get the meta-projects path (exported for use by other modules if needed)
   281→ */
   282→export function getMetaProjectsPath(): string {
   283→  return getMetaProjectsBasePath()
   284→}
   285→
