/**
 * API Module
 *
 * Provides a unified API client that works with both Electron IPC and HTTP transport.
 * Import from this module to get the appropriate client for your environment.
 */

import { Api } from './types'
import { ElectronBackend, isElectronAvailable } from './electron-backend'
import { HttpBackend } from './http-backend'

// =============================================================================
// API Instance Management
// =============================================================================

let apiInstance: Api | null = null

/**
 * Check if running in Electron environment with electronAPI available
 */
export function isElectronEnvironment(): boolean {
  return isElectronAvailable()
}

/**
 * Get the current API instance (may be null if not initialized)
 */
export function getApi(): Api | null {
  return apiInstance
}

/**
 * Initialize the API with the appropriate backend
 * - In Electron: Automatically uses ElectronBackend
 * - In browser/Capacitor: Requires config parameter for HttpBackend
 */
export function initializeApi(config?: { host: string; port: number; token: string }): Api {
  if (isElectronEnvironment()) {
    apiInstance = new ElectronBackend()
  } else if (config) {
    apiInstance = new HttpBackend(config)
  } else {
    throw new Error('HTTP backend requires connection config')
  }
  return apiInstance
}

/**
 * Set the API instance directly (useful for testing or custom backends)
 */
export function setApi(api: Api): void {
  apiInstance = api
}

/**
 * Clear the API instance
 */
export function clearApi(): void {
  apiInstance = null
}

// =============================================================================
// Re-export types and backends
// =============================================================================

export type { Api, ExtendedApi, ConnectionState, ApiBackendType } from './types'
export type {
  Settings,
  ProjectCategory,
  Project,
  OpenTab,
  TileLayout,
  Workspace,
  Session,
  VoiceSettings,
  PtyDataCallback,
  PtyExitCallback,
  PtyRecreatedCallback,
  ApiOpenSessionCallback,
  Unsubscribe,
  ApiContext
} from './types'

export { ElectronBackend, isElectronAvailable, getElectronBackend } from './electron-backend'
export { HttpBackend, createHttpBackend } from './http-backend'

// =============================================================================
// Host configuration - types and functions (legacy exports for compatibility)
// =============================================================================

export type { HostConfig } from './hostConfig'

export {
  getHostConfig,
  saveHostConfig,
  clearHostConfig,
  hasHostConfig,
  getDefaultConfig,
  buildBaseUrl,
  buildWsUrl,
  buildApiUrl,
  validateHostConfig,
  parseConnectionUrl,
  generateConnectionUrl
} from './hostConfig'

// =============================================================================
// HTTP Client exports (legacy compatibility)
// =============================================================================

export type {
  ApiClient,
  BeadsTask,
  BeadsCloseResult,
  GSDProgress
} from './httpClient'

export {
  HttpApiClient,
  getElectronAPI,
  createApiClient,
  getApiClient,
  setHttpClient
} from './httpClient'

import { create } from 'zustand'
import { clearProjectCaches } from '../utils/lruCache'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number
  apiAutoStart?: boolean
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'
  autoAcceptTools?: string[]
  permissionMode?: string
  color?: string
  ttsVoice?: string
  ttsEngine?: 'piper' | 'xtts'
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
  categoryId?: string
  order?: number
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

interface WorkspaceState {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  categories: ProjectCategory[]

  setProjects: (projects: Project[]) => void
  addProject: (project: Project) => void
  removeProject: (path: string) => void
  updateProject: (path: string, updates: Partial<Project>) => void

  addTab: (tab: OpenTab) => void
  removeTab: (id: string) => void
  updateTab: (id: string, updates: Partial<OpenTab>) => void
  setActiveTab: (id: string) => void
  clearTabs: () => void

  setCategories: (categories: ProjectCategory[]) => void
  addCategory: (name: string) => string
  updateCategory: (id: string, updates: Partial<ProjectCategory>) => void
  removeCategory: (id: string) => void
  reorderCategories: (ids: string[]) => void
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
}

const generateCategoryId = (): string =>
  `cat-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`

export const useWorkspaceStore = create<WorkspaceState>((set, get) => ({
  projects: [],
  openTabs: [],
  activeTabId: null,
  categories: [],

  setProjects: (projects) => set({ projects }),

  addProject: (project) => {
    const { projects } = get()
    if (!projects.find((p) => p.path === project.path)) {
      set({ projects: [...projects, project] })
    }
  },

  removeProject: (path) => {
    const { projects } = get()
    clearProjectCaches(path)
    set({ projects: projects.filter((p) => p.path !== path) })
  },

  updateProject: (path, updates) => {
    const { projects } = get()
    set({
      projects: projects.map((p) =>
        p.path === path ? { ...p, ...updates } : p
      )
    })
  },

  addTab: (tab) => {
    const { openTabs } = get()
    set({
      openTabs: [...openTabs, tab],
      activeTabId: tab.id
    })
  },

  removeTab: (id) => {
    const { openTabs, activeTabId } = get()
    const newTabs = openTabs.filter((t) => t.id !== id)
    let newActiveId = activeTabId

    if (activeTabId === id) {
      const index = openTabs.findIndex((t) => t.id === id)
      if (newTabs.length > 0) {
        newActiveId = newTabs[Math.min(index, newTabs.length - 1)].id
      } else {
        newActiveId = null
      }
    }

    set({ openTabs: newTabs, activeTabId: newActiveId })
  },

  updateTab: (id, updates) => {
    const { openTabs } = get()
    set({
      openTabs: openTabs.map((t) =>
        t.id === id ? { ...t, ...updates } : t
      )
    })
  },

  setActiveTab: (id) => set({ activeTabId: id }),

  clearTabs: () => set({ openTabs: [], activeTabId: null }),

  setCategories: (categories) => set({ categories }),

  addCategory: (name) => {
    const { categories } = get()
    const id = generateCategoryId()
    const maxOrder = categories.reduce((max, c) => Math.max(max, c.order), -1)
    set({
      categories: [...categories, { id, name, collapsed: false, order: maxOrder + 1 }]
    })
    return id
  },

  updateCategory: (id, updates) => {
    const { categories } = get()
    set({
      categories: categories.map((c) =>
        c.id === id ? { ...c, ...updates } : c
      )
    })
  },

  removeCategory: (id) => {
    const { categories, projects } = get()
    set({
      categories: categories.filter((c) => c.id !== id),
      projects: projects.map((p) =>
        p.categoryId === id ? { ...p, categoryId: undefined } : p
      )
    })
  },

  reorderCategories: (ids) => {
    const { categories } = get()
    set({
      categories: categories.map((c) => ({
        ...c,
        order: ids.indexOf(c.id)
      }))
    })
  },

  moveProjectToCategory: (projectPath, categoryId) => {
    const { projects } = get()
    const categoryProjects = projects.filter((p) =>
      categoryId === null ? !p.categoryId : p.categoryId === categoryId
    )
    const maxOrder = categoryProjects.reduce((max, p) => Math.max(max, p.order ?? -1), -1)
    set({
      projects: projects.map((p) =>
        p.path === projectPath
          ? { ...p, categoryId: categoryId ?? undefined, order: maxOrder + 1 }
          : p
      )
    })
  },

  reorderProjects: (categoryId, projectPaths) => {
    const { projects } = get()
    set({
      projects: projects.map((p) => {
        const index = projectPaths.indexOf(p.path)
        if (index >= 0) {
          return { ...p, order: index }
        }
        return p
      })
    })
  }
}))

import { useCallback, useRef } from 'react'
import { Project, useWorkspaceStore } from '../../stores/workspace.js'
import { SidebarState } from './useSidebarState.js'
import { SidebarProps } from './types.js'

// Use type assertion for extended electronAPI methods not in the base type
const electronAPI = window.electronAPI as (typeof window.electronAPI) & {
  selectExecutable?: () => Promise<string | null>
  runExecutable?: (executable: string, cwd: string) => Promise<{ success: boolean; error?: string }>
  getCategoryMetaPath?: (categoryName: string) => Promise<string>
  getMetaProjectsPath?: () => Promise<string>
}

export interface SidebarHandlers {
  // Project handlers
  handleSelectExecutable: (project: Project) => Promise<void>
  handleClearExecutable: (project: Project) => void
  handleRunExecutable: (project: Project) => Promise<void>

  // Rename handlers
  handleStartRename: (e: React.MouseEvent, project: Project) => void
  handleRenameSubmit: () => void
  handleRenameKeyDown: (e: React.KeyboardEvent) => void

  // Category handlers
  handleAddCategory: () => void
  handleOpenCategoryAsProject: (categoryName: string) => Promise<void>
  handleOpenAllProjects: () => Promise<void>
  handleStartCategoryRename: (
    category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]
  ) => void
  handleCategoryRenameSubmit: () => void
  handleCategoryRenameKeyDown: (e: React.KeyboardEvent) => void
  toggleCategoryCollapse: (categoryId: string) => void

  // Resize handler
  handleMouseDown: (e: React.MouseEvent) => void

  // Backdrop handler
  handleBackdropClick: () => void
}

export interface UseSidebarHandlersParams {
  state: SidebarState
  onUpdateProject: SidebarProps['onUpdateProject']
  onOpenSession: SidebarProps['onOpenSession']
  isMobile: boolean
  onMobileClose: (() => void) | undefined
}

export function useSidebarHandlers(params: UseSidebarHandlersParams): SidebarHandlers {
  const { state, onUpdateProject, onOpenSession, isMobile, onMobileClose } = params
  const {
    setContextMenu,
    editingProject,
    setEditingProject,
    editInputRef,
    editingCategory,
    setEditingCategory,
    categoryEditInputRef,
    addCategory,
    updateCategory,
    categories,
    setIsResizing,
    moveProjectToCategory,
  } = state

  // Project handlers
  const handleSelectExecutable = useCallback(
    async (project: Project) => {
      const executable = await electronAPI?.selectExecutable?.()
      if (executable) onUpdateProject(project.path, { executable })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleClearExecutable = useCallback(
    (project: Project) => {
      onUpdateProject(project.path, { executable: undefined })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleRunExecutable = useCallback(
    async (project: Project) => {
      if (project.executable) {
        const result = await electronAPI?.runExecutable?.(project.executable, project.path)
        if (result && !result.success) console.error('Failed to run executable:', result.error)
      }
      setContextMenu(null)
    },
    [setContextMenu]
  )

  // Rename handlers
  // Ref tracks cancel intent so blur handler can skip saving after Escape
  const renameCancelledRef = useRef(false)

  const handleStartRename = useCallback(
    (e: React.MouseEvent, project: Project) => {
      e.stopPropagation()
      renameCancelledRef.current = false
      setEditingProject({ path: project.path, name: project.name })
      setTimeout(() => editInputRef.current?.select(), 0)
    },
    [setEditingProject, editInputRef]
  )

  const handleRenameSubmit = useCallback(() => {
    if (renameCancelledRef.current) {
      renameCancelledRef.current = false
      return
    }
    if (editingProject && editingProject.name.trim()) {
      onUpdateProject(editingProject.path, { name: editingProject.name.trim() })
    }
    setEditingProject(null)
  }, [editingProject, onUpdateProject, setEditingProject])

  const handleRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleRenameSubmit()
      else if (e.key === 'Escape') {
        renameCancelledRef.current = true
        setEditingProject(null)
      }
    },
    [handleRenameSubmit, setEditingProject]
  )

  // Category handlers
  const handleAddCategory = useCallback(() => {
    const newId = addCategory('New Category')
    setEditingCategory({ id: newId, name: 'New Category' })
    setTimeout(() => categoryEditInputRef.current?.select(), 0)
  }, [addCategory, setEditingCategory, categoryEditInputRef])

  const handleOpenCategoryAsProject = useCallback(
    async (categoryName: string) => {
      const metaPath = await electronAPI?.getCategoryMetaPath?.(categoryName)
      if (metaPath) onOpenSession(metaPath)
    },
    [onOpenSession]
  )

  const handleOpenAllProjects = useCallback(async () => {
    const metaPath = await electronAPI?.getMetaProjectsPath?.()
    if (metaPath) onOpenSession(metaPath)
  }, [onOpenSession])

  // Category rename cancel ref (same pattern as project rename)
  const categoryRenameCancelledRef = useRef(false)

  const handleStartCategoryRename = useCallback(
    (category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]) => {
      categoryRenameCancelledRef.current = false
      setEditingCategory({ id: category.id, name: category.name })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [setEditingCategory, categoryEditInputRef]
  )

  const handleCategoryRenameSubmit = useCallback(() => {
    if (categoryRenameCancelledRef.current) {
      categoryRenameCancelledRef.current = false
      return
    }
    if (editingCategory && editingCategory.name.trim()) {
      updateCategory(editingCategory.id, { name: editingCategory.name.trim() })
    }
    setEditingCategory(null)
  }, [editingCategory, updateCategory, setEditingCategory])

  const handleCategoryRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleCategoryRenameSubmit()
      else if (e.key === 'Escape') {
        categoryRenameCancelledRef.current = true
        setEditingCategory(null)
      }
    },
    [handleCategoryRenameSubmit, setEditingCategory]
  )

  const toggleCategoryCollapse = useCallback(
    (categoryId: string) => {
      const category = categories.find((c) => c.id === categoryId)
      if (category) updateCategory(categoryId, { collapsed: !category.collapsed })
    },
    [categories, updateCategory]
  )

  // Resize handler
  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault()
      setIsResizing(true)
    },
    [setIsResizing]
  )

  // Backdrop handler
  const handleBackdropClick = useCallback(() => {
    if (isMobile && onMobileClose) {
      onMobileClose()
    }
  }, [isMobile, onMobileClose])

  return {
    handleSelectExecutable,
    handleClearExecutable,
    handleRunExecutable,
    handleStartRename,
    handleRenameSubmit,
    handleRenameKeyDown,
    handleAddCategory,
    handleOpenCategoryAsProject,
    handleOpenAllProjects,
    handleStartCategoryRename,
    handleCategoryRenameSubmit,
    handleCategoryRenameKeyDown,
    toggleCategoryCollapse,
    handleMouseDown,
    handleBackdropClick,
  }
}

// Helper for creating category with project
export function useCreateCategoryWithProject(
  state: SidebarState
): (projectPath: string) => void {
  const { addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef } = state

  return useCallback(
    (projectPath: string) => {
      const newId = addCategory('New Category')
      moveProjectToCategory(projectPath, newId)
      setContextMenu(null)
      setEditingCategory({ id: newId, name: 'New Category' })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef]
  )
}

import { useEffect, useCallback } from 'react'
import { Project } from '../../stores/workspace.js'
import { useSwipeGesture } from '../../hooks/useSwipeGesture.js'
import { SidebarState } from './useSidebarState.js'

// Use type assertion for extended electronAPI methods not in the base type
const electronAPI = window.electronAPI as (typeof window.electronAPI) & {
  apiStatus?: (projectPath: string) => Promise<{ running: boolean; port?: number }>
  beadsCheck?: (cwd: string) => Promise<{ installed: boolean; initialized: boolean }>
  beadsList?: (cwd: string) => Promise<{ success: boolean; tasks?: Array<{ status: string }>; error?: string }>
  isDebugMode?: () => Promise<boolean>
}

export interface UseSidebarEffectsParams {
  state: SidebarState
  projects: Project[]
  isMobile: boolean
  isMobileOpen: boolean | undefined
  onMobileClose: (() => void) | undefined
  onWidthChange: (width: number) => void
}

export function useSidebarEffects(params: UseSidebarEffectsParams): void {
  const { state, projects, isMobile, isMobileOpen, onMobileClose, onWidthChange } = params
  const {
    sidebarRef,
    isResizing,
    setIsResizing,
    contextMenu,
    categoryContextMenu,
    setContextMenu,
    setCategoryContextMenu,
    setApiStatus,
    setTaskCounts,
    focusedProjectPath,
    setIsDebugMode,
  } = state

  // Swipe to close on mobile (swipe left to close drawer)
  useSwipeGesture(sidebarRef, {
    onSwipeLeft: isMobile && isMobileOpen ? onMobileClose : undefined,
    threshold: 50,
  })

  // Resize handling
  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    setIsResizing(true)
  }, [setIsResizing])

  useEffect(() => {
    let rafId: number | null = null
    const handleMouseMove = (e: MouseEvent) => {
      if (!isResizing) return
      if (rafId !== null) return
      rafId = requestAnimationFrame(() => {
        rafId = null
        const newWidth = Math.min(Math.max(e.clientX, 200), 500)
        onWidthChange(newWidth)
      })
    }
    const handleMouseUp = () => setIsResizing(false)

    if (isResizing) {
      document.addEventListener('mousemove', handleMouseMove)
      document.addEventListener('mouseup', handleMouseUp)
      document.body.style.cursor = 'ew-resize'
      document.body.style.userSelect = 'none'
    }

    return () => {
      if (rafId !== null) cancelAnimationFrame(rafId)
      document.removeEventListener('mousemove', handleMouseMove)
      document.removeEventListener('mouseup', handleMouseUp)
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }
  }, [isResizing, onWidthChange, setIsResizing])

  // Close context menus on click
  useEffect(() => {
    const handleClick = () => {
      setContextMenu(null)
      setCategoryContextMenu(null)
    }
    if (contextMenu || categoryContextMenu) {
      document.addEventListener('click', handleClick)
      return () => document.removeEventListener('click', handleClick)
    }
  }, [contextMenu, categoryContextMenu, setContextMenu, setCategoryContextMenu])

  // Fetch API status when context menu opens
  useEffect(() => {
    if (contextMenu && electronAPI?.apiStatus) {
      electronAPI.apiStatus(contextMenu.project.path).then((status) => {
        setApiStatus((prev) => ({ ...prev, [contextMenu.project.path]: status }))
      })
    }
  }, [contextMenu, setApiStatus])

  // Fetch task counts for all projects
  useEffect(() => {
    async function fetchTaskCounts(): Promise<void> {
      if (!electronAPI?.beadsCheck) return
      const counts: Record<string, { open: number; inProgress: number }> = {}
      for (const project of projects) {
        try {
          const status = await electronAPI.beadsCheck(project.path)
          if (status.installed && status.initialized && electronAPI.beadsList) {
            const result = await electronAPI.beadsList(project.path)
            if (result.success && result.tasks) {
              const tasks = result.tasks as Array<{ status: string }>
              const open = tasks.filter((t) => t.status === 'open').length
              const inProgress = tasks.filter((t) => t.status === 'in_progress').length
              counts[project.path] = { open, inProgress }
            }
          }
        } catch {
          /* ignore */
        }
      }
      setTaskCounts(counts)
    }
    fetchTaskCounts()
    const interval = setInterval(fetchTaskCounts, 30000)
    return () => clearInterval(interval)
  }, [projects, setTaskCounts])

  // Fetch API status for focused project
  useEffect(() => {
    if (focusedProjectPath && electronAPI?.apiStatus) {
      electronAPI.apiStatus(focusedProjectPath).then((status) => {
        setApiStatus((prev) => ({ ...prev, [focusedProjectPath]: status }))
      })
    }
  }, [focusedProjectPath, setApiStatus])

  // Check debug mode on mount
  useEffect(() => {
    electronAPI?.isDebugMode?.()?.then(setIsDebugMode)
  }, [setIsDebugMode])

  // Export handleMouseDown for use in the component
  return
}

export function useResizeHandler(
  setIsResizing: (v: boolean) => void
): (e: React.MouseEvent) => void {
  return useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault()
      setIsResizing(true)
    },
    [setIsResizing]
  )
}

