/**
 * Electron backend implementation that delegates to window.electronAPI
 */
export class ElectronBackend implements ExtendedApi {
  /**
   * Check if the Electron API is available
   * @throws Error if electronAPI is not available
   */
  private checkApi(): void {
    if (!window.electronAPI) {
      throw new Error('Electron API not available. Are you running in Electron?')
    }
  }

  // ==========================================================================
  // PTY Management
  // ==========================================================================

  async spawnPty(cwd: string, sessionId?: string, model?: string, backend?: BackendId): Promise<string> {
    this.checkApi()
    return window.electronAPI!.spawnPty(cwd, sessionId, model, backend)
  }

  killPty(id: string): void {
    this.checkApi()
    window.electronAPI!.killPty(id)
  }

  writePty(id: string, data: string): void {
    this.checkApi()
    window.electronAPI!.writePty(id, data)
  }

  resizePty(id: string, cols: number, rows: number): void {
    this.checkApi()
    window.electronAPI!.resizePty(id, cols, rows)
  }

  onPtyData(id: string, callback: PtyDataCallback): Unsubscribe {
    this.checkApi()
    return window.electronAPI!.onPtyData(id, callback)
  }

  onPtyExit(id: string, callback: PtyExitCallback): Unsubscribe {
    this.checkApi()
    return window.electronAPI!.onPtyExit(id, callback)
  }

  onPtyRecreated(callback: PtyRecreatedCallback): Unsubscribe {
    this.checkApi()
    return window.electronAPI!.onPtyRecreated(callback)
  }

  setPtyBackend(id: string, backend: BackendId): Promise<void> {
    this.checkApi()
    return window.electronAPI!.setPtyBackend(id, backend)
  }

  // ==========================================================================
  // Session Management
  // ==========================================================================

  async discoverSessions(projectPath: string, backend?: BackendId): Promise<Session[]> {
    this.checkApi()
    return window.electronAPI!.discoverSessions(projectPath, backend)
  }

  // ==========================================================================
  // Workspace Management
  // ==========================================================================

  async getWorkspace(): Promise<Workspace> {
    this.checkApi()
    return window.electronAPI!.getWorkspace()
  }

  async saveWorkspace(workspace: Workspace): Promise<void> {
    this.checkApi()
    return window.electronAPI!.saveWorkspace(workspace)
  }

  // ==========================================================================
  // Settings Management
  // ==========================================================================

  async getSettings(): Promise<Settings> {
    this.checkApi()
    return window.electronAPI!.getSettings()
  }

  async saveSettings(settings: Settings): Promise<void> {
    this.checkApi()
    return window.electronAPI!.saveSettings(settings)
  }

  // ==========================================================================
  // Project Management
  // ==========================================================================

  async addProject(): Promise<string | null> {
    this.checkApi()
    return window.electronAPI!.addProject()
  }

  async addProjectsFromParent(): Promise<Array<{ path: string; name: string }> | null> {
    this.checkApi()
    return window.electronAPI!.addProjectsFromParent()
  }

  // ==========================================================================
  // TTS (Text-to-Speech)
  // ==========================================================================

  async ttsInstallInstructions(projectPath: string): Promise<{ success: boolean }> {
    this.checkApi()
    return window.electronAPI!.ttsInstallInstructions(projectPath)
  }

  async ttsSpeak(text: string): Promise<{ success: boolean; audioData?: string; error?: string }> {
    this.checkApi()
    return window.electronAPI!.voiceSpeak(text)
  }

  async ttsStop(): Promise<{ success: boolean }> {
    this.checkApi()
    return window.electronAPI!.voiceStopSpeaking()
  }

  // ==========================================================================
  // Events
  // ==========================================================================

  onApiOpenSession(callback: ApiOpenSessionCallback): Unsubscribe {
    this.checkApi()
    return window.electronAPI!.onApiOpenSession(callback)
  }

  // ==========================================================================
  // Extended API (Desktop-only features)
  // ==========================================================================

  async selectDirectory(): Promise<string | null> {
    this.checkApi()
    return window.electronAPI!.selectDirectory()
  }

  async selectExecutable(): Promise<string | null> {
    this.checkApi()
    return window.electronAPI!.selectExecutable()
  }

  windowMinimize(): void {
    this.checkApi()
    window.electronAPI!.windowMinimize()
  }

  windowMaximize(): void {
    this.checkApi()
    window.electronAPI!.windowMaximize()
  }

  windowClose(): void {
    this.checkApi()
    window.electronAPI!.windowClose()
  }

  async windowIsMaximized(): Promise<boolean> {
    this.checkApi()
    return window.electronAPI!.windowIsMaximized()
  }

  getPathForFile(file: File): string {
    this.checkApi()
    return window.electronAPI!.getPathForFile(file)

import React, { useEffect, useState, useCallback, useRef, RefObject } from 'react'
import { TitleBar } from '../components/TitleBar'
import { Sidebar } from '../components/Sidebar'
import { TerminalTabs } from '../components/TerminalTabs'
import { Terminal } from '../components/terminal/Terminal'
import { TiledTerminalView } from '../components/TiledTerminalView'
import { SettingsModal } from '../components/SettingsModal'
import { MakeProjectModal } from '../components/MakeProjectModal'
import { ErrorBoundary } from '../components/ErrorBoundary'
import { FileBrowser } from '../components/mobile/FileBrowser'
import type { HostConfig } from '../hooks/useHostConnection'
import { useWorkspaceStore } from '../stores/workspace'
import { useVoice } from '../contexts/VoiceContext'
import { useModals } from '../contexts/ModalContext'
import {
  useInstallation,
  useUpdater,
  useViewState,
  useWorkspaceLoader,
  useSessionPolling,
  useApiListeners,
  useProjectHandlers
} from '../hooks'
import type { Api } from '../api'
import { InstallationPrompt } from './InstallationPrompt'
import { MobileConnectModal } from './MobileConnectModal'

export interface MainAppProps {
  api: Api
  isElectron: boolean
  onDisconnect?: () => void
}

export function MainApp({ api, isElectron, onDisconnect }: MainAppProps): React.ReactElement {
  const {
    projects,
    openTabs,
    activeTabId,
    categories,
    addProject,
    removeProject,
    updateProject,
    addTab,
    removeTab,
    updateTab,
    setActiveTab
  } = useWorkspaceStore()

  const { voiceOutputEnabled, setProjectVoice } = useVoice()
  const voiceOutputEnabledRef = useRef(voiceOutputEnabled)

  // Modal state from context
  const { settingsOpen, makeProjectOpen, openSettings, closeSettings, openMakeProject, closeMakeProject } = useModals()

  // Installation state from hook
  const {
    claudeInstalled,
    npmInstalled,
    gitBashInstalled,
    installing,
    installError,
    installMessage,
    checkInstallation,
    handleInstallNode,
    handleInstallGit,
    handleInstallClaude
  } = useInstallation()

  // Updater state from hook
  const { appVersion, updateStatus, downloadUpdate, installUpdate } = useUpdater()

  // View state from hook
  const {
    viewMode,
    tileLayout,
    lastFocusedTabId,
    sidebarWidth,
    sidebarCollapsed,
    setViewMode,
    setTileLayout,
    setLastFocusedTabId,
    setSidebarWidth,
    setSidebarCollapsed,
    toggleViewMode
  } = useViewState()

  // Workspace loader hook
  const {
    loading,
    currentTheme,
    settings,
    setCurrentTheme,
    setSettings
  } = useWorkspaceLoader({
    api,
    checkInstallation,
    setViewMode,
    setTileLayout
  })

  // Session polling hook
  useSessionPolling({ api, openTabs, updateTab })

  // API listeners hook
  useApiListeners({
    api,
    projects,
    settings,
    addTab,
    updateTab,
    setActiveTab
  })

  // Project handlers hook
  const {
    handleAddProject,
    handleAddProjectsFromParent,
    handleOpenSession,
    handleOpenSessionAtPosition,
    handleCloseTab,
    handleCloseProjectTabs,
    handleProjectCreated,
    handleUndoCloseTab,
    canUndoCloseTab
  } = useProjectHandlers({
    api,
    projects,
    openTabs,
    settings,
    tileLayout,
    addProject,
    removeTab,
    addTab,
    setActiveTab,
    setTileLayout
  })

  // App-specific state
  const [mobileDrawerOpen, setMobileDrawerOpen] = useState(false)
  const [mobileConnectOpen, setMobileConnectOpen] = useState(false)
  const [showFileBrowser, setShowFileBrowser] = useState(false)
  const [fileBrowserPath, setFileBrowserPath] = useState<string | null>(null)
  const hadProjectsRef = useRef(false)
  const terminalContainerRef = useRef<HTMLDivElement>(null)

  // Keep ref in sync for callbacks
  useEffect(() => {
    voiceOutputEnabledRef.current = voiceOutputEnabled
  }, [voiceOutputEnabled])

  // Apply per-project voice settings when active tab changes
  useEffect(() => {
    if (!activeTabId) {
      setProjectVoice(null)
      return
    }
    const activeTab = openTabs.find(t => t.id === activeTabId)
    if (!activeTab) {
      setProjectVoice(null)
      return
    }
    const project = projects.find(p => p.path === activeTab.projectPath)
    if (project?.ttsVoice && project?.ttsEngine) {
      setProjectVoice({ ttsVoice: project.ttsVoice, ttsEngine: project.ttsEngine })
    } else {
      setProjectVoice(null)
    }
  }, [activeTabId, openTabs, projects, setProjectVoice])

  // Save workspace when it changes
  useEffect(() => {
    if (!loading) {
      const hadProjects = sessionStorage.getItem('hadProjects') === 'true' || hadProjectsRef.current

      if (projects.length === 0 && hadProjects) {
        console.warn('Skipping save: projects empty but previously had projects (likely hot reload)')
        return
      }

      if (projects.length > 0) {
        hadProjectsRef.current = true
        sessionStorage.setItem('hadProjects', 'true')
      }

      api.saveWorkspace({
        projects,
        openTabs: openTabs.map(t => ({
          id: t.id,
          projectPath: t.projectPath,
          sessionId: t.sessionId,
          title: t.title,
          ptyId: t.ptyId,
          backend: t.backend
        })),
        activeTabId,
        viewMode,
        tileLayout,
        categories
      })
    }
  }, [api, projects, openTabs, activeTabId, loading, viewMode, tileLayout, categories])

  // Mobile drawer handlers
  const openMobileDrawer = useCallback(() => {
    setMobileDrawerOpen(true)
  }, [])

  const closeMobileDrawer = useCallback(() => {
    setMobileDrawerOpen(false)
  }, [])

  // Open file browser (mobile only)
  const handleOpenFileBrowser = useCallback((projectPath?: string) => {
    setFileBrowserPath(projectPath || null)
    setShowFileBrowser(true)
  }, [])

  if (loading) {
    return (
      <div className="app">
        <div className="empty-state" role="status" aria-live="polite">
          <p>Loading...</p>
        </div>
      </div>
    )
  }

  const isMobile = !isElectron

  return (
    <div className="app">
      <TitleBar />
      <div className="app-content">
        <Sidebar
          projects={projects}
          openTabs={openTabs}
          activeTabId={activeTabId}
          lastFocusedTabId={lastFocusedTabId}
          onAddProject={handleAddProject}
          onAddProjectsFromParent={handleAddProjectsFromParent}
          onRemoveProject={removeProject}
          onOpenSession={handleOpenSession}
          onSwitchToTab={setActiveTab}
          onOpenSettings={openSettings}
          onOpenMakeProject={openMakeProject}
          onUpdateProject={updateProject}
          onCloseProjectTabs={handleCloseProjectTabs}
          width={sidebarWidth}
          collapsed={sidebarCollapsed}
          onWidthChange={setSidebarWidth}

