import { useEffect, useRef, useState, useCallback } from 'react'
import type { Api } from '../api'
import type { BackendId } from '../api/types'
import type { AppSettings } from './useSettings'
import { useWorkspaceStore } from '../stores/workspace'
import { Theme, getThemeById, applyTheme, themes } from '../themes'
import { cleanupOrphanedBuffers } from '../components/terminal/Terminal'

interface UseWorkspaceLoaderOptions {
  api: Api
  checkInstallation: () => Promise<void>
  setViewMode: (mode: 'tabs' | 'tiled') => void
  setTileLayout: (layout: any[]) => void
}

interface UseWorkspaceLoaderReturn {
  loading: boolean
  currentTheme: Theme
  settings: AppSettings | null
  setCurrentTheme: (theme: Theme) => void
  setSettings: (settings: AppSettings | null) => void
}

export function useWorkspaceLoader({
  api,
  checkInstallation,
  setViewMode,
  setTileLayout
}: UseWorkspaceLoaderOptions): UseWorkspaceLoaderReturn {
  const {
    setProjects,
    setCategories,
    addTab,
    clearTabs
  } = useWorkspaceStore()

  const [loading, setLoading] = useState(true)
  const [currentTheme, setCurrentTheme] = useState<Theme>(themes[0])
  const [settings, setSettings] = useState<AppSettings | null>(null)
  const initRef = useRef(false)
  const hadProjectsRef = useRef(false)

  // Load workspace on mount and restore tabs
  useEffect(() => {
    // Prevent double initialization from StrictMode
    if (initRef.current) return
    initRef.current = true

    const loadWorkspace = async () => {
      try {
        // Check if Claude, npm, and git-bash are installed
        await checkInstallation()

        // Load and apply theme with any saved customizations
        const loadedSettings = await api.getSettings()
        setSettings(loadedSettings)
        const theme = getThemeById(loadedSettings.theme || 'default')
        applyTheme(theme, loadedSettings.themeCustomization)
        setCurrentTheme(theme)

        // Kill any existing PTYs from hot reload (but don't clear buffers - they'll be restored)
        const existingTabs = useWorkspaceStore.getState().openTabs
        for (const tab of existingTabs) {
          api.killPty(tab.id)
        }
        clearTabs()

        const workspace = await api.getWorkspace()
        if (workspace.projects) {
          setProjects(workspace.projects)
          if (workspace.projects.length > 0) {
            hadProjectsRef.current = true
          }
          // Install TTS instructions for all existing projects
          for (const project of workspace.projects) {
            await api.ttsInstallInstructions?.(project.path)
          }
        }
        // Load categories
        if (workspace.categories) {
          setCategories(workspace.categories)
        }

        // Restore previously open tabs (only if not already open)
        // Track old ID -> new ID mapping for layout restoration
        const idMapping = new Map<string, string>()

        if (workspace.openTabs && workspace.openTabs.length > 0) {
          const currentTabs = useWorkspaceStore.getState().openTabs
          const usedSessionIds = new Set(currentTabs.map(t => t.sessionId).filter(Boolean))
          const sessionsCache = new Map<string, { list: { sessionId: string; slug: string }[]; nextIndex: number }>()

          for (const savedTab of workspace.openTabs) {
            try {
              // Always install TTS instructions so Claude uses <tts> tags
              await api.ttsInstallInstructions?.(savedTab.projectPath)

              const projectName = savedTab.projectPath.split(/[/\\]/).pop() || savedTab.projectPath
              let titleToRestore = savedTab.title || `${projectName} - New`

              // Get project and determine effective backend for restored tab
              const projectForTab = workspace.projects?.find((p: { path: string }) => p.path === savedTab.projectPath)
              const savedBackend = savedTab.backend
              const effectiveBackendForTab = (savedBackend
                || (projectForTab?.backend && projectForTab.backend !== 'default'
                  ? projectForTab.backend
                  : (loadedSettings?.backend && loadedSettings.backend !== 'default'
                    ? loadedSettings.backend
                    : 'claude'))) as BackendId

              let sessionIdToRestore: string | undefined = savedTab.sessionId

              // Always discover sessions to find the most recent one
              let sessionsForProject = sessionsCache.get(savedTab.projectPath)
              if (!sessionsForProject) {
                const list = await api.discoverSessions(savedTab.projectPath, effectiveBackendForTab)
                sessionsForProject = { list, nextIndex: 0 }
                sessionsCache.set(savedTab.projectPath, sessionsForProject)
              }

              const list = sessionsForProject.list || []
              for (let i = sessionsForProject.nextIndex; i < list.length; i++) {
                const candidate = list[i]
                if (!usedSessionIds.has(candidate.sessionId)) {
                  sessionIdToRestore = candidate.sessionId
                  titleToRestore = `${projectName} - ${candidate.slug}`
                  sessionsForProject.nextIndex = i + 1
                  break
                }
              }

              const ptyId = await api.spawnPty(
                savedTab.projectPath,
                sessionIdToRestore,
                undefined,
                effectiveBackendForTab
              )
              if (savedTab.id) {
                idMapping.set(savedTab.id, ptyId)
              }

              addTab({
                id: ptyId,
                projectPath: savedTab.projectPath,
                sessionId: sessionIdToRestore,
                title: titleToRestore,
                ptyId,
                backend: effectiveBackendForTab
              })
              if (sessionIdToRestore) {
                usedSessionIds.add(sessionIdToRestore)
              }
            } catch (e) {
              console.error('Failed to restore tab:', savedTab.projectPath, e)
            }
          }
        }

        // Clean up orphaned terminal buffers from previous session/HMR
        const activeTabIds = useWorkspaceStore.getState().openTabs.map(t => t.id)
        cleanupOrphanedBuffers(activeTabIds)

        // Restore view mode
        if (workspace.viewMode) {
          setViewMode(workspace.viewMode)
        }
        // Restore tileLayout with mapped IDs and migrate legacy format
        if (workspace.tileLayout && workspace.tileLayout.length > 0 && idMapping.size > 0) {
          const mappedLayout = workspace.tileLayout
            .map(tile => {
              // Migrate legacy tiles: add tabIds/activeTabId if missing
              const tabIds = tile.tabIds || [tile.id]
              const mappedTabIds = tabIds
                .map(id => idMapping.get(id) || id)
                .filter(id => {
                  // Only keep tab IDs that exist in the current session
                  const currentTabs = useWorkspaceStore.getState().openTabs
                  return currentTabs.some(t => t.id === id)
                })

              if (mappedTabIds.length === 0) return null

              const newId = idMapping.get(tile.id) || mappedTabIds[0]
              const activeTabId = tile.activeTabId
                ? (idMapping.get(tile.activeTabId) || mappedTabIds[0])
                : mappedTabIds[0]

              return {
                ...tile,
                id: newId,
                tabIds: mappedTabIds,
                activeTabId
              }
            })
            .filter((tile): tile is NonNullable<typeof tile> => tile !== null)

          if (mappedLayout.length > 0) {
            setTileLayout(mappedLayout)
          }
        }
      } catch (e) {
        console.error('Failed to load workspace:', e)
      }
      setLoading(false)
    }
    loadWorkspace()
  }, [api, addTab, clearTabs, checkInstallation, setProjects, setCategories, setViewMode, setTileLayout])

  return {
    loading,
    currentTheme,
    settings,
    setCurrentTheme,
    setSettings
  }
}

import { useState, useCallback, useRef } from 'react'
import { Project } from '../../../stores/workspace.js'
import { DropTarget } from '../types.js'

interface UseDragAndDropOptions {
  projects: Project[]
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
  reorderCategories: (categoryIds: string[]) => void
  categories: Array<{ id: string; name: string; order: number; collapsed?: boolean }>
}

interface UseDragAndDropReturn {
  draggedProject: string | null
  draggedCategory: string | null
  dropTarget: DropTarget | null
  handleProjectDragStart: (e: React.DragEvent, projectPath: string) => void
  handleProjectDragEnd: () => void
  handleCategoryDragOver: (e: React.DragEvent, categoryId: string | null) => void
  handleCategoryDrop: (e: React.DragEvent, categoryId: string | null) => void
  handleProjectDragOver: (
    e: React.DragEvent,
    projectPath: string,
    position: 'before' | 'after'
  ) => void
  handleProjectDrop: (
    e: React.DragEvent,
    targetPath: string,
    targetCategoryId: string | undefined
  ) => void
  handleCategoryDragStart: (e: React.DragEvent, categoryId: string) => void
  handleCategoryDragEnd: () => void
  handleCategoryHeaderDragOver: (
    e: React.DragEvent,
    targetCategoryId: string,
    position: 'before' | 'after'
  ) => void
  handleCategoryHeaderDrop: (e: React.DragEvent, targetCategoryId: string) => void
}

export function useDragAndDrop({
  projects,
  moveProjectToCategory,
  reorderProjects,
  reorderCategories,
  categories,
}: UseDragAndDropOptions): UseDragAndDropReturn {
  const [draggedProject, setDraggedProject] = useState<string | null>(null)
  const [draggedCategory, setDraggedCategory] = useState<string | null>(null)
  const [dropTarget, setDropTarget] = useState<DropTarget | null>(null)
  // Ref tracks the latest dropTarget so drop handlers always read fresh position
  // (state in the closure may be stale if React hasn't re-rendered since the last dragOver)
  const dropTargetRef = useRef<DropTarget | null>(null)

  const handleProjectDragStart = useCallback((e: React.DragEvent, projectPath: string) => {
    setDraggedProject(projectPath)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', projectPath)
    // Also set custom type so TiledTerminalView can detect sidebar project drags
    e.dataTransfer.setData('application/x-sidebar-project', projectPath)
  }, [])

  const handleProjectDragEnd = useCallback(() => {
    setDraggedProject(null)
    setDropTarget(null)
    dropTargetRef.current = null
  }, [])

  const handleCategoryDragOver = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject) {
        const target: DropTarget = {
          type: categoryId ? 'category' : 'uncategorized',
          id: categoryId,
        }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedProject]
  )

  const handleCategoryDrop = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      if (draggedProject) {
        moveProjectToCategory(draggedProject, categoryId)
      }
      setDraggedProject(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedProject, moveProjectToCategory]
  )

  const handleProjectDragOver = useCallback(
    (e: React.DragEvent, projectPath: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.stopPropagation()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject && draggedProject !== projectPath) {
        const target: DropTarget = { type: 'project', id: projectPath, position }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedProject]
  )

  const handleProjectDrop = useCallback(
    (e: React.DragEvent, targetPath: string, targetCategoryId: string | undefined) => {
      e.preventDefault()
      e.stopPropagation()

      if (draggedProject && draggedProject !== targetPath) {
        const draggedProjectData = projects.find((p) => p.path === draggedProject)
        const targetProject = projects.find((p) => p.path === targetPath)

        if (draggedProjectData && targetProject) {
          moveProjectToCategory(draggedProject, targetCategoryId ?? null)
          const categoryProjects = projects
            .filter((p) =>
              targetCategoryId ? p.categoryId === targetCategoryId : !p.categoryId
            )
            .sort((a, b) => (a.order ?? 0) - (b.order ?? 0))
            .map((p) => p.path)

          const newOrder = categoryProjects.filter((p) => p !== draggedProject)
          const targetIndex = newOrder.indexOf(targetPath)
          // Read from ref to get the latest position (state may be stale)
          const currentDropTarget = dropTargetRef.current
          const insertIndex = currentDropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
          newOrder.splice(insertIndex, 0, draggedProject)
          reorderProjects(targetCategoryId ?? null, newOrder)
        }
      }
      setDraggedProject(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedProject, projects, moveProjectToCategory, reorderProjects]
  )

  const handleCategoryDragStart = useCallback((e: React.DragEvent, categoryId: string) => {
    setDraggedCategory(categoryId)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', categoryId)
  }, [])

  const handleCategoryDragEnd = useCallback(() => {
    setDraggedCategory(null)
    setDropTarget(null)
    dropTargetRef.current = null
  }, [])

  const handleCategoryHeaderDragOver = useCallback(
    (e: React.DragEvent, targetCategoryId: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        const target: DropTarget = { type: 'category', id: targetCategoryId, position }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedCategory]
  )

  const handleCategoryHeaderDrop = useCallback(
    (e: React.DragEvent, targetCategoryId: string) => {
      e.preventDefault()
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        const orderedCategories = [...categories].sort((a, b) => a.order - b.order)
        const categoryIds = orderedCategories.map((c) => c.id)
        const newOrder = categoryIds.filter((id) => id !== draggedCategory)
        const targetIndex = newOrder.indexOf(targetCategoryId)
        // Read from ref to get the latest position (state may be stale)
        const currentDropTarget = dropTargetRef.current
        const insertIndex = currentDropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
        newOrder.splice(insertIndex, 0, draggedCategory)
        reorderCategories(newOrder)
      }
      setDraggedCategory(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedCategory, categories, reorderCategories]
  )

  return {
    draggedProject,
    draggedCategory,
    dropTarget,
    handleProjectDragStart,
    handleProjectDragEnd,
    handleCategoryDragOver,
    handleCategoryDrop,
    handleProjectDragOver,
    handleProjectDrop,
    handleCategoryDragStart,
    handleCategoryDragEnd,
    handleCategoryHeaderDragOver,
    handleCategoryHeaderDrop,
  }
}
